// // This module decrements a 6-bit address counter from an initial value of 36 (6'b100100) on each positive clock edge, provided a decrement signal (dec) is asserted. If the counter reaches a minimum value of 32 (6'b100000), it resets to the starting value of 36.
module top_module(clk, cnt, res, address);input clk, res, cnt;

	output wire[5:0] address;

	reg[5:0] internAddr;

	always @(posedge clk) begin

		if (res)
			internAddr <= 6'b100000;
		else if (cnt)
			internAddr <= (internAddr == 6'b100100) ? 6'b100000 : (internAddr + 1);

	end

	assign address = internAddr;

endmodule
